logger = logging.getLogger(__name__)

class ScoutCrewCore:
    REQUIRED_PACKAGES = {
        'langchain': '0.0.1',
        'numpy': '1.21.0',
        'pandas': '1.3.0',
        'datetime': None
    }

    def __init__(self):
        self.performance_monitor = QueryPerformanceMonitor()
        self.verify_dependencies()

    @classmethod
    def verify_dependencies(cls) -> None:
        missing = []
        outdated = []

        for package, min_version in cls.REQUIRED_PACKAGES.items():
            try:
                if min_version:
                    installed = pkg_resources.get_distribution(package)
                    if pkg_resources.parse_version(installed.version) < pkg_resources.parse_version(min_version):
                        outdated.append(f'{package} (installed: {installed.version}, required: {min_version})')
                else:
                    importlib.import_module(package)
            except (pkg_resources.DistributionNotFound, ImportError) as e:
                missing.append(package)
                logger.error(f'Failed to import {package}: {str(e)}')

        if missing or outdated:
            raise DependencyError(f'Dependencies issue: Missing: {missing}, Outdated: {outdated}')

    def safe_execute_query(self, query_func):
        @functools.wraps(query_func)
        def wrapper(*args, **kwargs):
            start_time = datetime.now()
            try:
                result = query_func(*args, **kwargs)
                execution_time = (datetime.now() - start_time).total_seconds()
                self.performance_monitor.record_query(result, execution_time)
                return result
            except Exception as e:
                logger.error(f'Query execution failed: {str(e)}')
                self.performance_monitor.record_error(str(e))
                raise QueryExecutionError(f'Failed to execute query: {str(e)}')
        return wrapper

class QueryPerformanceMonitor:
    def __init__(self, history_limit: int = 1000):
        self.history_limit = history_limit
        self.metrics: Dict[str, float] = {
            'query_count': 0,
            'success_rate': 0.0,
            'avg_response_time': 0.0,
            'error_count': 0
        }
        self.query_history: List[Dict] = []
        self.error_history: List[Dict] = []

    def record_query(self, query_result: any, execution_time: float) -> None:
        self.metrics['query_count'] += 1
        query_data = {
            'timestamp': datetime.now(),
            'success': hasattr(query_result, 'status') and query_result.status == 'success',
            'execution_time': execution_time,
            'result_count': len(query_result.items) if hasattr(query_result, 'items') else 0
        }
        self._add_to_history(self.query_history, query_data)
        self._update_metrics()

    def record_error(self, error_message: str) -> None:
        self.metrics['error_count'] += 1
        error_data = {
            'timestamp': datetime.now(),
            'error_message': error_message
        }
        self._add_to_history(self.error_history, error_data)

    def _add_to_history(self, history: List[Dict], data: Dict) -> None:
        history.append(data)
        if len(history) > self.history_limit:
            history.pop(0)

    def _update_metrics(self) -> None:
        recent_queries = self.query_history[-100:] if len(self.query_history) > 100 else self.query_history
        if recent_queries:
            self.metrics['success_rate'] = sum(q['success'] for q in recent_queries) / len(recent_queries)
            self.metrics['avg_response_time'] = statistics.mean(q['execution_time'] for q in recent_queries)

    def get_performance_report(self) -> Dict:
        return {
            'metrics': self.metrics.copy(),
            'recent_errors': self.error_history[-5:],
            'performance_trend': self._calculate_performance_trend()
        }

    def _calculate_performance_trend(self) -> Dict:
        if len(self.query_history) < 2:
            return {'trend': 'insufficient_data'}

        recent_success_rate = self.metrics['success_rate']
        previous_success_rate = sum(q['success'] for q in self.query_history[:-100]) / len(self.query_history[:-100]) if len(self.query_history) > 100 else 0

        return {
            'trend': 'improving' if recent_success_rate > previous_success_rate else 'degrading',
            'change_rate': recent_success_rate - previous_success_rate
        }

